INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 1, 'Língua Portuguesa', 'Geral', 'Observe o trecho abaixo, que aborda diferenças entre a língua escrita e a língua falada: “Mas por que falamos de um modo, na fala propriamente dita, e falamos, na escrita, de outro, tão diferente do registro anterior, que afinal lhe deu origem? É consenso que as dificuldades principais são oferecidas pela gramática, cujo conceito dominante é de que seja um rol de regras...” A afirmação correta sobre a estruturação e o significado desse pequeno texto, é:', ARRAY['a pergunta feita no texto não é respondida;', 'a gramática é bem-vista pelo autor do texto;', 'o pronome “que”, sublinhado no texto, se refere à língua escrita;', 'há um ensinamento no texto que nos diz que a língua escrita deu origem à língua falada;', 'ao dizer que é um “consenso”, o autor do texto nos informa que nem todos pensam da mesma forma.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 2, 'Língua Portuguesa', 'Geral', 'Os animais estão presentes, como referência, em nossa linguagem diária; a expressão sublinhada abaixo que mostra seu significado corretamente indicado, é:', ARRAY['o jornalista considerou a instituição um ninho de cobras / um lugar perigoso para a saúde;', 'o comandante soltou cobras e lagartos do trabalho realizado / aspectos sigilosos;', 'o presidente considerou a atitude do ministro como uma cachorrada / um ato violento;', 'os jornais diziam que a assembleia espanhola estava cheia de ratos / gente desonesta;', 'os namorados estavam como dois pombinhos / aquecendo-se repetidamente.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 3, 'Língua Portuguesa', 'Geral', 'Numa viagem de carro entre Rio e Minas Gerais, um motorista foi observando uma série de cartazes na rodovia; o único cartaz abaixo que está corretamente redigido, é:', ARRAY['Precisam-se de caminhões para transporte de grãos;', 'Há vagas no estassionamento ao lado do posto;', 'Aqui anteriormente haviam árvores; hoje, um deserto;', 'Deixe para amanhã o que não precisa fazer hoje;', 'Local de diverção para crianças.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 4, 'Língua Portuguesa', 'Geral', 'A frase abaixo cujo termo sublinhado exerce a função sintática de objeto direto, é:', ARRAY['Viu-se o acidente de longe;', 'Necessita-se de transporte rápido;', 'Alugamos ontem o apartamento;', 'O navio atracou atrasado no cais;', 'O menino não gostava de algodão doce.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 5, 'Língua Portuguesa', 'Geral', 'Em todos os períodos abaixo há duas orações: a opção em que a segunda oração mostra uma consequência da primeira, é:', ARRAY['Só ficou contente, quando todos os amigos chegaram;', 'O turista visitaria a igreja, se houvesse tempo para isso;', 'Ninguém saiu do prédio porque faltava segurança;', 'Todos os sinais estavam apagados, por faltar energia;', 'Choveu tanto durante a noite, que as ruas se alagaram.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 6, 'Língua Portuguesa', 'Geral', 'A frase abaixo em que a utilização do acento grave indicativo da crase está feita de forma correta, é:', ARRAY['Para manter a saúde é necessário começar à amar;', 'A mente, como à casa, é mobiliada pelo proprietário;', 'Sou igual à vara de marmelo. Envergo, mas não quebro;', 'Outro dia fui para à academia, mas não gosto de malhar;', 'Um pouco de incenso queimado é bom remédio para reajustas às coisas.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 7, 'Língua Portuguesa', 'Geral', 'A frase abaixo em que o emprego do termo sublinhado está adequado, é:', ARRAY['Ele não sabia que era impossível. Foi lá e fez;', 'Fui fazer a confissão e quando saí de lá, estava aliviado;', 'O problema em ser pontual é que ninguém está lá para apreciar isso;', 'Para se chegar ao topo é difícil, mas, ao se chegar lá, a vista é belíssima;', 'O filme a que assistimos era muito bom, mas quando saímos de lá, o tempo tinha mudado e chovia muito.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 8, 'Língua Portuguesa', 'Geral', 'A frase abaixo em que os dois adjetivos nela destacados representam estados, é:', ARRAY['Homem resfriado não deve ficar deitado;', 'É um milagre divino que a curiosidade sobreviva à educação formal;', 'O objetivo da educação é substituir uma mente vazia por uma mente aberta;', 'Nossas necessidades são poucas, mas nossos desejos são incontáveis;', 'Não se pode descobrir novas terras sem aceitar perder de vista a terra por um longo tempo.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 9, 'Língua Portuguesa', 'Geral', 'A frase abaixo que mostra um mesmo vocábulo empregado sucessivamente como substantivo abstrato e concreto, é:', ARRAY['Este livro vai falar do amor e dos amores de minha vida;', 'Trouxe lembranças para todos, pois viajei com a lembrança de vocês;', 'O fato de fazerem tantos agrados aos convidados não foi do meu agrado;', 'As marcas deixadas na paisagem eram marcas de descuido e de irresponsabilidade;', 'Os cuidados com os ferimentos dos soldados mostraram o cuidado com os cidadãos em geral.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 10, 'Língua Portuguesa', 'Geral', 'A frase abaixo que mostra corretamente um sinônimo da palavra sublinhada na frase, é:', ARRAY['Filhos casam, crescem e nos dão netos / aumentam;', 'A preocupação traz a velhice antes da hora / antiguidade;', 'A distância mais longa é entre a cabeça e o coração / larga;', 'Nada chegará ao fundo da risada de uma criança / estudante;', 'A maioria dos homens morre de seus remédios, e não das suas doenças / enfermidades.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 11, 'Matemática Básica', 'Geral', 'A média aritmética de 7 números inteiros consecutivos começados em N é igual a M. A média aritmética dos 7 números inteiros consecutivos começados em M é igual a:', ARRAY['N;', 'N + 3;', 'N + 6;', 'N + 7;', 'N + 9.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 12, 'Matemática Básica', 'Geral', 'Quatro objetos, A, B, C e D, possuem pesos diferentes. Sabe-se que: • A é mais pesado que B. • C é mais leve que A. • D é mais leve que B, mas não é o mais leve de todos. É correto concluir que:', ARRAY['A não é o mais pesado de todos;', 'B é mais leve que D;', 'C é mais pesado que B;', 'C é mais leve que D;', 'B é mais leve que C.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 13, 'Matemática Básica', 'Geral', 'Em um encontro de 7 pessoas, 4 delas se conheciam mutuamente e as outras 3 não conheciam ninguém. Pessoas que se conheciam se cumprimentaram com um abraço e pessoas que não se conheciam se cumprimentaram com um aperto de mãos. O número de apertos de mãos que ocorreram nesse encontro foi:', ARRAY['3;', '7;', '12;', '14;', '15.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 14, 'Matemática Básica', 'Geral', 'Um número menos a sua terça parte é igual à sua metade mais 3 unidades. A soma dos algarismos desse número é:', ARRAY['6;', '7;', '8;', '9;', '10.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 15, 'Matemática Básica', 'Geral', 'Patrícia tem 33 moedas, sendo algumas de R$ 0,25, outras de R$ 0,50 e as demais de R$ 1,00. No total, as moedas de Patrícia somam R$ 19,00 e ela tem 5 moedas de R$ 1,00 a mais do que moedas de R$ 0,50. O número de moedas de R$ 0,25 que Patrícia tem é:', ARRAY['16;', '14;', '12;', '10;', '8.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 16, 'Matemática Básica', 'Geral', 'Certa série de televisão tem 3 temporadas. Cada temporada contém 6 episódios e cada episódio dura exatamente 42 minutos. O tempo total de duração dessa série é de:', ARRAY['12 horas e 10 minutos;', '12 horas e 36 minutos;', '12 horas e 42 minutos;', '13 horas e 18 minutos;', '13 horas e 32 minutos.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 17, 'Matemática Básica', 'Geral', 'Mariana comprou um vestido com 15% de desconto e pagou R$ 221,00. O valor do desconto foi de:', ARRAY['R$ 39,00;', 'R$ 38,50;', 'R$ 35,60;', 'R$ 33,15;', 'R$ 32,10.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 18, 'Matemática Básica', 'Geral', 'Em um novo loteamento, Paulo comprou um lote retangular de 540 metros quadrados medindo 18 metros de frente para a rua. Para a segurança de seu terreno, ele pretende cercá-lo com três voltas de arame farpado, e a loja de materiais vende o arame em rolos de comprimentos múltiplos de 50 metros. Para realizar seu objetivo, o rolo de arame farpado mais econômico que Paulo deve comprar tem:', ARRAY['200 m;', '250 m;', '300 m;', '350 m;', '400 m.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 19, 'Matemática Básica', 'Geral', 'Em uma urna A há 6 bolas iguais numeradas de 1 a 6 e em uma urna B há 7 bolas, também iguais, numeradas de 7 a 13. Retira-se aleatoriamente uma bola de cada urna. A probabilidade de a soma dos números das bolas sorteadas ser maior do que 16 é:', ARRAY['6 13;', '5 14;', '1 6;', '1 7;', '2 21.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 20, 'Matemática Básica', 'Geral', 'Duas fazendas A e B são vizinhas. Sabe-se que 3 4 ⁄  da área da fazenda A está plantada com soja e que 2 5 ⁄  da área da fazenda B está plantada com soja. Sabe-se ainda que a área da fazenda B é uma vez e meia a área da fazenda A. A fração da área total das duas fazendas que está plantada com soja é:', ARRAY['8 15 ;', '13 20 ;', '14 25 ;', '33 40 ;', '27 50.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 21, 'Direitos Humanos', 'Geral', 'A Declaração Universal dos Direitos Humanos, proclamada há 75 anos, apresenta diretrizes básicas dos direitos e liberdades de todos os seres humanos. Está em desacordo com o citado documento a norma que estabelece que:', ARRAY['ninguém será mantido em escravidão ou servidão; a escravidão e o tráfico de escravos serão proibidos em todas as suas formas;', 'ninguém será submetido à tortura, nem a tratamento ou castigo cruel, desumano ou degradante, salvo para resgate de vítima viva de crime hediondo;', 'todo ser humano tem direito a receber dos tribunais nacionais competentes remédio efetivo para os atos que violem os direitos fundamentais que lhe sejam reconhecidos pela Constituição ou pela lei;', 'todo ser humano acusado de um ato delituoso tem o direito de ser presumido inocente até que a sua culpabilidade tenha sido provada, de acordo com a lei, em julgamento público no qual lhe tenham sido asseguradas todas as garantias necessárias à sua defesa;', 'todo ser humano tem capacidade para gozar os direitos e as liberdades estabelecidos na citada Declaração, sem distinção de qualquer espécie, seja de raça, cor, sexo, língua, religião, opinião política ou de outra natureza, origem nacional ou social, riqueza, nascimento, ou qualquer outra condição.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 22, 'Direitos Humanos', 'Geral', 'O policial militar João, aprovado no último concurso para ingresso na corporação, participou de sua primeira operação policial na favela Alfa. Após ter conseguido remover barricadas colocadas por criminosos em via pública para impedir a entrada da polícia, o PM João e sua equipe chegaram na principal rua da localidade, onde informes de inteligência da polícia apontavam residir agentes do crime conhecidos como “vapores” do tráfico de droga, isto é, pessoas que venderiam entorpecentes no varejo, diretamente aos consumidores. Apesar de não contar com qualquer mandado judicial e não estar configurada situação flagrancial, o PM João indagou ao PM responsável pela operação se poderia adentrar a força em determinada casa, ocasião em que lhe foi respondido:', ARRAY['positivamente, pois a casa é asilo de violabilidade relativa do indivíduo, ninguém nela podendo penetrar sem consentimento do morador, salvo por ordem policial ou judicial;', 'positivamente, pois a casa é asilo inviolável do indivíduo, ninguém nela podendo penetrar sem consentimento do morador, salvo em caso de suspeita por informe de inteligência policial, flagrante delito ou por determinação judicial;', 'negativamente, pois a casa é asilo inviolável do indivíduo, ninguém nela podendo penetrar sem consentimento do morador, salvo em caso de flagrante delito ou desastre, ou para prestar socorro, ou, durante o dia, por determinação judicial;', 'negativamente, pois a casa é asilo inviolável do indivíduo, ninguém nela podendo penetrar sem consentimento do morador, salvo em caso de flagrante delito, desastre, determinação judicial ou autorização do Ministério Público;', 'negativamente, pois a casa é asilo de violabilidade relativa do indivíduo, ninguém nela podendo penetrar sem consentimento do morador, salvo em situação de flagrante delito, por ordem judicial ou por força de operação policial, desde que previamente comunicada ao Ministério Público.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 23, 'Direitos Humanos', 'Geral', 'Com o advento da Emenda Constitucional nº 45 de 2004, ocorreu a alteração do regramento sobre a internalização de normas internacionais de direitos humanos. Nesse sentido, com relação ao atual entendimento do Supremo Tribunal Federal sobre o assunto, é correto afirmar que:', ARRAY['os tratados internacionais de direitos humanos têm natureza de lei ordinária federal;', 'as normas internacionais que versam sobre direitos humanos têm o mesmo status das normas constitucionais, sendo incorporadas automaticamente ao âmbito interno;', 'as convenções internacionais de direitos humanos são ratificadas pelo chefe do Congresso Nacional, que poderá revogar a assinatura firmada pelo presidente da República;', 'as normas internacionais de direitos humanos não prevalecem sobre os direitos previstos nas normas constitucionais vigentes anteriormente à sua ratificação e aprovação pelo Congresso Nacional;', 'as convenções e os tratados internacionais de direitos humanos têm natureza supralegal, salvo na hipótese de serem equivalentes às emendas constitucionais, uma vez aprovadas pelo mesmo rito especial.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 24, 'Direitos Humanos', 'Geral', 'O jovem André, negro, de 19 anos e morador da favela Beta, quando chegava em sua casa vindo da faculdade, foi preso em flagrante pelo policial militar José. O PM deu voz de prisão a André exclusivamente pelo jovem estar portando uma mochila preta, haja vista que a senhora Maria narrara ao policial, minutos antes, que seu celular acabara de ser roubado por uma pessoa que portava uma mochila preta. O PM André levou o jovem até a rua de trás e perguntou a Maria se ele era o autor do crime. Mesmo com resposta categoricamente negativa da vítima e não tendo sido encontrado o aparelho de celular, o PM André manteve a prisão, levou o jovem até a delegacia, onde o Delegado de Polícia Pedro lavrou auto de prisão em flagrante pelo crime de roubo. No caso em tela, de acordo com a Constituição da República, a prisão ilegal de André será:', ARRAY['imediatamente revogada pelo Ministério Público;', 'imediatamente relaxada pela autoridade judiciária;', 'revogada, em até 48h (quarenta e oito horas), por meio de habeas corpus;', 'anulada, em até 72h (setenta e duas horas), pelo Tribunal de Justiça.', 'objeto de conversão em liberdade provisória, no prazo de 24h (vinte e quatro horas) por autoridade competente da polícia, do Judiciário ou do Ministério Público.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 25, 'Direitos Humanos', 'Geral', 'O Estado brasileiro aderiu à Convenção Americana de Direitos Humanos (Pacto de São José da Costa Rica), reconhecendo o sistema criado pela Organização dos Estados Americanos (OEA). De acordo com a citada convenção:', ARRAY['o sistema interamericano é formado pela Comissão Interamericana de Direitos Humanos e pelo Tribunal Penal Internacional;', 'a jurisdição da Corte Interamericana de Direitos Humanos é aplicável desde 1988 e foi reconhecida pelo Brasil com a promulgação da Constituição da República vigente;', 'a realização de audiência de custódia é um ato ilegal, porque submete o investigado a mais uma camada de controle sobre o ilícito penal que lhe é imputado;', 'a pessoa detida pela prática de crimes deve ser informada das razões da sua detenção e notificada, no prazo de trinta dias, da acusação formulada contra ela, para que possa constituir advogado ou defensor público;', 'ninguém deve ser detido por dívida, mas esse princípio não limita os mandados de autoridade judiciária competente expedidos em virtude de inadimplemento de obrigação alimentar.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 26, 'Direitos Humanos', 'Geral', 'A Lei nº 13.445, de 24 de maio de 2017, instituiu a Lei de Migração, dispondo sobre os direitos e os deveres do migrante e do visitante, regulando a sua entrada e estada no País e estabelecendo princípios e diretrizes para as políticas públicas para o emigrante. Consoante dispõe o citado diploma legal:', ARRAY['ao migrante é garantida no território nacional, em condição de igualdade com os nacionais, a inviolabilidade do direito à vida, à liberdade, à igualdade, à segurança e à propriedade;', 'a situação migratória deverá ser determinante na análise do alcance dos direitos e garantias previstos na referida lei, na Constituição Federal e nos tratados vigentes;', 'a realização de expulsão ou de deportação coletivas deverão ser fomentadas nas situações de migrações numerosas, que geram grave impacto na economia nacional;', 'o migrante e o refugiado não poderão frequentar a escola pública, pois sua nacionalidade ou condição migratória podem configurar grave risco aos demais alunos;', 'a política migratória observará o princípio do fomento ao retorno do migrante ao seu país de origem, independentemente das condições que ocasionaram a sua saída, sendo exceção a política de regularização documental.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 27, 'Direitos Humanos', 'Geral', 'No ano de 2010, o Rio de Janeiro foi o primeiro estado da federação a instituir um sistema estadual de prevenção e combate à tortura no âmbito do Poder Legislativo, com a constituição de um comitê estadual e um mecanismo estadual de prevenção e combate à tortura. Sobre o Sistema Nacional de Prevenção e Combate à Tortura (SNPCT), é correto afirmar que:', ARRAY['as corregedorias e ouvidorias de polícia não poderão integrar o SNPCT, uma vez que serão fiscalizadas pelo referido sistema e deverão prestar informações quando requisitadas;', 'uma de suas diretrizes é o respeito aos direitos humanos, mas os das pessoas privadas de liberdade devem ser relativizados, inclusive com prevalência dos direitos das vítimas;', 'o SNPCT atuará em preponderância às demais esferas de governo e de poder, responsáveis pela segurança pública, pela custódia de pessoas privadas de liberdade, por locais de internação de longa permanência e pela proteção de direitos humanos;', 'está em desacordo com o Protocolo Facultativo à Convenção das Nações Unidas contra a Tortura e Outros Tratamentos ou Penas Cruéis, Desumanos ou Degradantes, promulgado pelo Decreto nº 6.085, de 19 de abril de 2007, pois permite tortura vigiada por médicos nos casos de imprescindível obtenção de prova de crime;', 'é composto pelo Comitê Nacional de Prevenção e Combate à Tortura (CNPCT), pelo Mecanismo Nacional de Prevenção e Combate à Tortura (MNPCT), pelo Conselho Nacional de Política Criminal e Penitenciária (CNPCP) e pelo órgão do Ministério da Justiça responsável pelo sistema penitenciário nacional.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 28, 'Direitos Humanos', 'Geral', 'Neiva, uma idosa de 68 anos, é detida pela polícia local após ser suspeita de envolvimento em um furto. Durante sua audiência de custódia, ela alega ter sido vítima de tortura por parte dos policiais. Neiva afirma que foi submetida a diversas formas de agressão física e psicológica enquanto estava sob custódia. Ela relata que, após sua prisão, foi levada para uma sala isolada, onde os policiais começaram a interrogá-la de maneira agressiva, utilizando força física para obter informações. Neiva menciona ter sido espancada, ameaçada de morte e submetida a choques elétricos. Os policiais, por outro lado, negam as acusações de tortura, alegando que agiram de acordo com os procedimentos padrões para obter informações cruciais para a investigação. Eles afirmam que a força foi usada apenas quando necessário para garantir a segurança e a cooperação de Neiva na elucidação do crime. No caso em tela, de acordo com a Lei Federal nº 9.455/1997, que define os crimes de tortura:', ARRAY['as condutas praticadas pelos policiais podem configurar o crime de tortura, na hipótese de comprovação dos fatos narrados por Neiva;', 'os policiais poderão ter as penas diminuídas, uma vez que são agentes públicos, caso respondam pela prática do crime de tortura;', 'os policiais não poderão ser acusados do suposto crime de tortura, em razão da presunção de veracidade de suas alegações;', 'os policiais atuaram sob o manto de uma excludente de ilicitude, uma vez que o uso da força teve por finalidade a comprovação da prática de um crime;', 'os policiais não poderão perder os seus cargos, sendo afastados das suas funções de patrulhamento para um trabalho burocrático, na hipótese de condenação pelo crime de tortura, de acordo com a lei.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 29, 'Direitos Humanos', 'Geral', 'Observe, a seguir, a prática dos seguintes crimes: I- João, de forma livre e consciente, realizou transferência, à força, de crianças do grupo para outro grupo com intenção de destruir, no todo ou em parte, um grupo nacional, étnico, racial ou religioso, enquanto tal. II- Maria, de forma livre e consciente, praticou desaparecimento forçado de pessoas, cometido no quadro de um ataque, generalizado ou sistemático, contra qualquer população civil, havendo conhecimento desse ataque. Para efeitos do Estatuto de Roma do Tribunal Penal Internacional (TPI) promulgado pelo Decreto nº 4.388/2002, João e Maria praticaram, respectivamente, crimes:', ARRAY['de sequestro e de guerra;', 'contra a vida e de genocídio;', 'de genocídio e contra a humanidade;', 'de guerra e de tortura;', 'contra infância e contra a pessoa.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 30, 'Direitos Humanos', 'Geral', 'João, um jovem de 23 anos, compareceu à ouvidoria da polícia e alegou ter sido vítima de abuso policial, haja vista que policiais militares fizeram uso de arma de fogo contra seu veículo, mesmo levando em consideração que João, de fato, desrespeitou bloqueio policial em via pública. Considerando o disposto na Lei Federal nº 13.060/2014, que disciplina o uso dos instrumentos de menor potencial ofensivo pelos agentes de segurança pública em todo o território nacional, no caso em tela, os policiais agiram de forma:', ARRAY['legítima, caso a conduta de João tenha representado risco de morte ou lesão aos agentes de segurança pública ou a terceiros;', 'legítima, pois qualquer desobediência a bloqueio policial em via pública dá ensejo a emprego de arma de fogo;', 'legítima, desde que tenha havido prévia autorização pelo superior hierárquico responsável pela ação policial para o uso de arma de fogo;', 'ilegítima, em qualquer hipótese, pois desobediência a bloqueio policial em via pública não dá ensejo a emprego de arma de fogo, em qualquer hipótese;', 'ilegítima, salvo se os policiais militares estivessem usando câmeras corporais que filmaram a conduta de João, independentemente de risco de morte ou lesão aos agentes de segurança pública ou a terceiros.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 31, 'Legislação Aplicada à PMERJ', 'Geral', 'João, policial militar, foi convocado para fazer o policiamento ostensivo durante a inauguração de uma obra realizada no Município Alfa, com a presença do prefeito da cidade e do governador do estado. Ao se apresentar para o serviço, o agente da lei percebe que não há, no local, qualquer promoção pessoal dos políticos presentes no evento. Na verdade, todas as informações atinentes à obra têm caráter educativo e informativo. Considerando o entendimento doutrinário e jurisprudencial dominantes, se está diante de uma manifestação do princípio da:', ARRAY['proporcionalidade;', 'impessoalidade;', 'continuidade;', 'juridicidade;', 'legalidade.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 32, 'Legislação Aplicada à PMERJ', 'Geral', '1º cenário: A Administração Pública, após a observância das formalidades legais, aplicou uma multa à sociedade empresária XYZ, contratada para fornecer bens ao Poder Público, em razão do descumprimento de cláusulas contratuais. 2º cenário: o policial militar Petrônio, após o exercício do contraditório e da ampla defesa, recebeu uma sanção disciplinar, por descumprir ordens legais do seu superior hierárquico. Considerando o entendimento doutrinário e jurisprudencial dominantes, as punições aplicadas à sociedade empresária XYZ e ao policial militar Petrônio são, respectivamente, manifestações do:', ARRAY['poder disciplinar e poder hierárquico;', 'poder hierárquico e poder disciplinar;', 'poder disciplinar e poder disciplinar;', 'poder de polícia e poder disciplinar;', 'poder de polícia e poder de polícia.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 33, 'Legislação Aplicada à PMERJ', 'Geral', 'Diversas pessoas, insatisfeitas com a crise econômica vivenciada no Estado Alfa, resolveram fechar ruas para protestar contra o governo. Após horas de manifestação pacífica, a passeata se tornou violenta, com a depredação do patrimônio público. Em assim sendo, dezenas de policiais militares foram convocados, pondo fim aos eventos. Considerando o entendimento doutrinário e jurisprudencial dominantes, os policiais militares puderam interromper a passeata, mesmo sem a manifestação do Poder Judiciário, em razão da:', ARRAY['presunção relativa de veracidade dos atos administrativos;', 'autoexecutoriedade dos atos administrativos;', 'imperatividade dos atos administrativos;', 'coercibilidade dos atos administrativos;', 'exigibilidade dos atos administrativos.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 34, 'Legislação Aplicada à PMERJ', 'Geral', 'João, policial no âmbito da Polícia Militar do Estado do Rio de Janeiro, conduzia uma viatura em alta velocidade durante perseguição a Tício, que tinha acabado de roubar um automóvel. Nesse contexto, o agente da lei colidiu com o veículo automotor de Caio, particular, o qual manifestou o interesse em ingressar, em juízo, com uma ação indenizatória para se ressarcir dos prejuízos suportados. Caio, então, procurou um advogado, que lhe informou que o Estado do Rio de Janeiro é uma pessoa jurídica de direito público, enquanto a Polícia Militar é um órgão público. Considerando o entendimento doutrinário e jurisprudencial dominantes, o particular deverá ingressar com a ação indenizatória em face do (da):', ARRAY['policial João, pois o Estado do Rio de Janeiro e a Polícia Militar não podem ser demandados por ato praticado por policial militar;', 'Estado do Rio de Janeiro, pois a Polícia Militar, enquanto órgão público, não pode, como regra, demandar, tampouco ser demandada;', 'Estado do Rio de Janeiro ou da Polícia Militar, pois ambos, como regra, podem demandar e ser demandados;', 'Polícia Militar, que pode, como regra, ser demandada, muito embora não possa demandar;', 'Polícia Militar, que pode, como regra, demandar e ser demandada.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 35, 'Legislação Aplicada à PMERJ', 'Geral', 'Após um desastre natural de grandes proporções, o efetivo da Polícia Militar e de todos os demais órgãos públicos do Estado Alfa está integralmente destacado para auxiliar no resgate de sobreviventes. João, que não tem qualquer vínculo com o Poder Público, verifica que Mévia está se afogando. Em assim sendo, o indivíduo, espontaneamente, auxilia e salva a mulher. Considerando o entendimento doutrinário, João exerceu a função pública na qualidade de:', ARRAY['particular em colaboração com o estado;', 'agente público de direito putativo;', 'agente público de fato necessário;', 'agente público de fato putativo;', 'servidor público temporário.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 36, 'Legislação Aplicada à PMERJ', 'Geral', 'Caio, grande apreciador de armas de fogo, perguntou ao seu irmão, policial militar, quais procedimentos deveria adotar para possuir um revólver, de forma regular, em seu domicílio. O agente da lei, então, explicou, detalhadamente, o caminho que deveria ser percorrido por Caio. Após a observância de todas as formalidades legais, a Administração Pública editou um ato administrativo, manifestando a concordância com o pedido formulado por Caio, autorizando-o a ter a posse de uma arma de fogo em seu domicílio. Considerando o entendimento doutrinário e jurisprudencial dominantes, está-se diante de um ato administrativo (de):', ARRAY['enunciativo;', 'ordinatório;', 'normativo;', 'controle;', 'negocial.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 37, 'Legislação Aplicada à PMERJ', 'Geral', 'João, policial militar, está em gozo de licença para tratar de interesse particular, ocasião em que, em observância às formalidades legais, a autoridade competente decreta estado de emergência. Preocupado e aproveitando o cenário posto, o policial consulta a legislação de regência, para analisar eventuais repercussões práticas que a medida terá sobre o seu licenciamento e sobre outras licenças. Considerando as disposições da Lei Estadual nº 443/1981 (Estatuto dos Policiais Militares), a decretação de estado de emergência poderá ensejar a interrupção da licença:', ARRAY['especial, para tratar de interesse particular e para tratamento de saúde de pessoa da família;', 'especial e para tratamento de saúde de pessoa da família;', 'para tratamento de saúde de pessoa da família, apenas;', 'especial e para tratar de interesse particular;', 'para tratar de interesse particular, apenas.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 38, 'Legislação Aplicada à PMERJ', 'Geral', 'Tício, policial militar, foi afastado do cargo, na esfera administrativa e após a observância de todas as formalidades legais, ao argumento de que a sua atuação demonstrou incapacidade no exercício de funções policiais-militares inerentes à posição ocupada. Considerando as disposições da Lei Estadual nº 443/1981 (Estatuto dos Policiais Militares), Tício foi afastado do cargo pelo:', ARRAY['presidente da Assembleia Legislativa;', 'comandante geral da Polícia Militar;', 'secretário de estado da Casa Civil;', 'presidente do Tribunal de Justiça;', 'vice-governador do estado.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 39, 'Legislação Aplicada à PMERJ', 'Geral', 'João, após ingressar na Polícia Militar do Estado do Rio de Janeiro, busca informações sobre a existência de eventual grupo que defenda as prerrogativas dos policiais, vindo a ser informado, por colegas de farda, sobre a matéria. Nesse cenário, considerando as disposições da Constituição do Estado do Rio de Janeiro, é possível a criação de:', ARRAY['associação de natureza não sindical, sem fins lucrativos, admitindo-se a greve, na forma da lei;', 'sindicato ou de associação, sem fins lucrativos, admitindo-se a greve, na forma da lei;', 'associação de natureza não sindical, sem fins lucrativos, vedando-se a greve;', 'sindicato ou de associação, sem fins lucrativos, vedando-se a greve;', 'sindicato ou de associação, com fins lucrativos, vedando-se a greve.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 40, 'Legislação Aplicada à PMERJ', 'Geral', 'João, oficial da Polícia Militar do Estado do Rio de Janeiro, é transferido para a reserva remunerada, enquanto Caio, praça, é demitido após a observância de todas as formalidades legais. Nesse cenário, considerando as disposições da Lei Estadual nº 443/1981 (Estatuto dos Policiais Militares), é correto afirmar que a(s) exclusão(ões) de:', ARRAY['João do serviço ativo será processada após a expedição de ato do comandante geral da Polícia Militar. Por outro lado, a exclusão de Caio do serviço ativo pressupõe a expedição de ato pelo comandante do batalhão ao qual está vinculado;', 'João do serviço ativo será processada após a expedição de ato do governador do estado. Por outro lado, a exclusão de Caio do serviço ativo pressupõe a expedição de ato pelo comandante do batalhão ao qual está vinculado;', 'João do serviço ativo será processada após a expedição de ato do governador do estado. Por outro lado, a exclusão de Caio do serviço ativo pressupõe a expedição de ato pelo comandante geral da Polícia Militar;', 'João e de Caio do serviço ativo serão processadas após a expedição de atos do comandante geral da Polícia Militar;', 'João e de Caio do serviço ativo serão processadas após a expedição de atos do governador do estado. Noções de Direito Penal e Processual Penal'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 41, 'Legislação Aplicada à PMERJ', 'Geral', 'Caio e João, policiais militares, realizavam policiamento ostensivo, ocasião em que, observando as formalidades legais, abordaram Tício, mas nada de ilícito foi arrecadado com o agente. Em conversa com os policiais, Tício afirmou que está cumprindo pena, em uma colônia agrícola, em razão de um crime perpetrado no passado. Considerando as disposições do Código Penal, Tício está cumprindo pena no regime:', ARRAY['semiaberto, sendo certo que o trabalho externo é admissível;', 'semiaberto, sendo certo que o trabalho externo é proibido;', 'fechado, sendo certo que o trabalho externo é admissível;', 'aberto, sendo certo que o trabalho externo é admissível;', 'aberto, sendo certo que o trabalho externo é proibido.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 42, 'Legislação Aplicada à PMERJ', 'Geral', 'Após receberem informações no sentido de que um homem estaria agredindo a sua esposa, policiais militares dirigiram-se ao domicílio do casal, e viram Tício correndo com um facão na direção de Mévia, afirmando que a mataria. Ato contínuo, a mulher, policial civil, efetuou um disparo de arma de fogo em direção a Tício, matando-o. Considerando as disposições do Código Penal, Mévia não responderá por qualquer crime, tendo agido sob o manto do (da):', ARRAY['exercício regular de um direito, causa de exclusão de tipicidade;', 'inexigibilidade de conduta diversa, causa de exclusão de ilicitude;', 'estrito cumprimento do dever legal, causa de exclusão de tipicidade;', 'estado de necessidade, causa de exclusão de ilicitude;', 'legítima defesa, causa de exclusão de ilicitude.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 43, 'Legislação Aplicada à PMERJ', 'Geral', '1º cenário: Tício ingressou no jardim de uma residência e escalou o muro do imóvel, com o objetivo de adentrar o local e proceder à subtração de diversos bens. Contudo, o agente viu uma pequena criança brincando com o pai, motivo pelo qual mudou de ideia e deixou a localidade. 2º cenário: Mévio desferiu diversos socos no rosto do seu desafeto, ocasião em que o último pediu por clemência. Muito embora pudesse continuar agredindo-o, Mévio interrompeu os atos e fugiu da localidade. Considerando as disposições do Código Penal, Tício e Mévio somente responderão pelos atos já praticados, respectivamente, em razão do (da):', ARRAY['arrependimento posterior e arrependimento posterior;', 'arrependimento eficaz e arrependimento posterior;', 'desistência voluntária e arrependimento posterior;', 'arrependimento eficaz e arrependimento eficaz;', 'desistência voluntária e desistência voluntária.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 44, 'Legislação Aplicada à PMERJ', 'Geral', 'João e Caio, policiais militares, foram chamados para atender a uma ocorrência de furto em um estabelecimento comercial no Município do Rio de Janeiro. Ao chegarem ao local dos fatos, Tício, autor do crime, encontrava-se clara e completamente embriagado, tendo afirmado aos policiais que teria tomado diversas doses de tequila para criar coragem para praticar o crime. Considerando as disposições do Código Penal, é correto afirmar que Tício:', ARRAY['responderá pelo crime praticado, pois a embriaguez voluntária pelo álcool não exclui a imputabilidade penal, salvo se o agente demonstrar que, ao tempo da ação, era inteiramente incapaz de entender o caráter ilícito do fato e de determinar-se de acordo com esse entendimento;', 'responderá pelo crime praticado, pois a embriaguez voluntária pelo álcool não exclui a imputabilidade penal. A sua pena, contudo, será reduzida, se o agente demonstrar que não possuía a plena capacidade de entender o caráter ilícito do seu comportamento;', 'não responderá pelo crime praticado, se o agente demonstrar que não possuía a plena capacidade de entender o caráter ilícito do seu comportamento;', 'não responderá pelo crime praticado, pois a embriaguez completa exclui a imputabilidade penal;', 'responderá pelo crime praticado, com pena agravada, pois a embriaguez voluntária pelo álcool não exclui a imputabilidade penal.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 45, 'Legislação Aplicada à PMERJ', 'Geral', 'João e Caio, policiais militares, realizavam patrulhamento de rotina, ocasião em que foram abordados por Maria, que lhes disse que um indivíduo, chamado Tício, a obrigou, mediante o emprego de arma de fogo, a adentrar o seu automóvel. Ato contínuo, o criminoso levou a vítima a uma agência bancária e determinou que ela colocasse a senha no caixa, para sacar o numerário disponível, evadindo-se na sequência, após 30 minutos com a vítima em seu poder. A partir da descrição física fornecida pela vítima, os policiais militares iniciaram as buscas e conseguiram prender Tício em flagrante. Considerando as disposições do Código Penal, Tício responderá pelo crime de:', ARRAY['extorsão mediante sequestro;', 'extorsão indireta;', 'latrocínio;', 'extorsão, mediante restrição de liberdade da vítima;', 'roubo.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 46, 'Legislação Aplicada à PMERJ', 'Geral', 'Caio e João, policiais militares, realizavam patrulhamento de rotina, ocasião em que, em observância às formalidades legais, abordaram Tício, com ele encontrando 600 gramas de cocaína. Cientificado dos seus direitos constitucionais, o agente confessou ser traficante, oferecendo R$ 5.000,00 para cada policial, caso o liberassem. Considerando as disposições do Código Penal, Tício, além do tráfico de drogas, responderá pelo crime de:', ARRAY['excesso de exação;', 'corrupção passiva;', 'corrupção ativa;', 'concussão;', 'peculato.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 47, 'Legislação Aplicada à PMERJ', 'Geral', 'Thiago, delegado de polícia, tomou conhecimento de que, na circunscrição da sua unidade policial, houve o roubo de um caminhão da loja XYZ, com a subtração da integralidade da carga que estava em seu interior, o que gerou forte repercussão na imprensa local. Considerando as disposições do Código de Processo Penal, a autoridade policial deflagrará um inquérito policial:', ARRAY['mediante requisição do Ministro da Justiça, pois o crime de roubo é persequível mediante ação penal pública condicionada à representação;', 'mediante representação do ofendido, pois o crime de roubo é persequível mediante ação penal pública condicionada à representação;', 'mediante requerimento do Ministério Público, que é o titular exclusivo da ação penal de iniciativa pública;', 'de ofício, pois o crime de roubo é persequível mediante ação penal pública incondicionada;', 'de ofício, desde que comprove a forte repercussão dos fatos na imprensa local.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 48, 'Legislação Aplicada à PMERJ', 'Geral', 'Dois policiais militares realizavam patrulhamento de rotina, ocasião em que visualizaram um homem com uma arma de fogo apontada para a cabeça de uma mulher, visando à subtração dos bens dela. Em assim sendo, os agentes da lei se aproximaram em silêncio e lograram êxito em desarmar Tício, que estava cometendo um crime patrimonial em detrimento de Maria. Considerando as disposições do Código de Processo Penal, Tício foi preso em flagrante:', ARRAY['presumido;', 'preparado;', 'impróprio;', 'esperado;', 'próprio.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 49, 'Legislação Aplicada à PMERJ', 'Geral', 'Caio e João, policiais militares, compareceram ao imóvel de Joana, que afirmou que teria sido injuriada por Tício, Mévio e Petrônio, seus vizinhos, que ofenderam a sua dignidade. Contudo, Joana afirmou que pretendia ingressar com uma queixa-crime apenas em face de Tício, pois teria um bom relacionamento com os demais vizinhos. Considerando as disposições do Código de Processo Penal, a queixa contra qualquer dos autores do crime obrigará ao processo de todos em razão do princípio da:', ARRAY['intranscendência;', 'indisponibilidade;', 'obrigatoriedade;', 'indivisibilidade;', 'oficialidade.'], 0);
INSERT INTO questoes (exam_id, question_number, subject, topic, text, options, correct_option_index) VALUES ('pmerj-2024', 50, 'Legislação Aplicada à PMERJ', 'Geral', 'Caio e João, policiais militares, prenderam Tício em flagrante, pela suposta prática do crime de furto qualificado, encaminhando-o à Delegacia de Polícia, onde prestaram depoimento na qualidade de testemunha. Na data designada para a instrução processual, na persecução penal em juízo, os policiais militares não puderam ser ouvidos, por estarem em uma complexa operação policial em andamento. O Ministério Público, então, dispensou a oitiva dos agentes da lei e pediu a condenação do acusado Tício, exclusivamente, com base nos depoimentos prestados, em sede policial, por Caio e João. Considerando as disposições do Código de Processo Penal, é correto afirmar que o juiz:', ARRAY['não poderá condenar Tício com base nos depoimentos prestados por Caio e João em sede policial, pois o magistrado deve formar a sua convicção pela livre apreciação da prova produzida em contraditório judicial, não podendo fundamentar sua decisão exclusivamente nos elementos informativos colhidos na investigação, ressalvadas as provas cautelares, não repetíveis e antecipadas;', 'não poderá condenar Tício com base nos depoimentos prestados por Caio e João em sede policial, pois o magistrado deve formar a sua convicção pela livre apreciação da prova produzida em contraditório judicial, não podendo fundamentar sua decisão exclusivamente nos elementos informativos colhidos na investigação ou em provas cautelares, não repetíveis e antecipadas;', 'poderá condenar Tício com base nos depoimentos prestados por Caio e João em sede policial, em razão do sistema do livre convencimento motivado;', 'poderá condenar Tício com base nos depoimentos prestados por Caio e João em sede policial, em razão do sistema da íntima convicção;', 'poderá condenar Tício com base nos depoimentos prestados por Caio e João em sede policial, em razão do sistema da prova tarifada. Tipo 1  Branca RASCUNHO Tipo 1  Branca RASCUNHO Tipo 1  Branca RASCUNHO Realização'], 0);